import React, { useState, useEffect } from 'react';
import Navbar from '../../components/common/Navbar';
import GlassCard from '../../components/common/GlassCard';
import { Users, BookOpen, DollarSign, Activity, CheckCircle, Clock } from 'lucide-react';

const AdminDashboard = () => {
    const [stats, setStats] = useState({
        totalUsers: 0,
        parents: 0,
        sitters: 0,
        activeReservations: 0,
        totalIncome: 0,
        pendingPayments: 0
    });
    const [recentActivity, setRecentActivity] = useState([]);
    const [paymentsBySitter, setPaymentsBySitter] = useState([]);

    useEffect(() => {
        // Real logic reading from localStorage exclusively to reflect exact system state
        const allUsers = JSON.parse(localStorage.getItem('users') || '[]');
        // In our auth mock, users registered via the form are in 'mockUsers'. 
        // But since we use useAuth login which sets a user session, let's also read 'registered_users' if they exist.
        // Actually, the register form uses the API, which we mocked. Let's assume users from API aren't perfectly synced to localstorage 
        // unless we added them. Let's just use what's in localstorage 'users' or default to 0 if none.

        const parents = allUsers.filter(u => u.role === 'parent').length;
        const sitters = allUsers.filter(u => u.role === 'sitter').length;

        const reqs = JSON.parse(localStorage.getItem('booking_requests') || '[]');
        const active = reqs.filter(r => r.status === 'CONFIRMADO').length;
        const pendingPay = reqs.filter(r => r.status === 'PAGADO').length;
        const completed = reqs.filter(r => r.status === 'COMPLETADO');

        // Calculate income (10% commission of completed requests)
        let income = 0;
        completed.forEach(r => {
            income += (r.total * 0.10);
        });

        setStats({
            totalUsers: allUsers.length,
            parents,
            sitters,
            activeReservations: active,
            totalIncome: income,
            pendingPayments: pendingPay
        });

        // Generate payments by sitter table
        const sitterMap = {};
        completed.forEach(r => {
            if(!sitterMap[r.sitterName]) {
                sitterMap[r.sitterName] = { name: r.sitterName, totalGenerated: 0, commission: 0, completedJobs: 0 };
            }
            sitterMap[r.sitterName].totalGenerated += r.total;
            sitterMap[r.sitterName].commission += (r.total * 0.10);
            sitterMap[r.sitterName].completedJobs += 1;
        });
        setPaymentsBySitter(Object.values(sitterMap));

        // Generate recent activity
        const activity = reqs.map(r => ({
            id: r.id,
            time: 'Reciente',
            title: r.status === 'COMPLETADO' ? 'Reserva Completada' : r.status === 'CONFIRMADO' ? 'Reserva Confirmada' : 'Actividad',
            desc: r.status === 'COMPLETADO' 
                ? `${r.parentName} pagó $${r.total} (Comisión: $${(r.total * 0.10).toFixed(2)})`
                : `${r.parentName} solicitó a ${r.sitterName}`,
            color: r.status === 'COMPLETADO' ? 'bg-secondary' : r.status === 'CONFIRMADO' ? 'bg-primary' : 'bg-yellow-500'
        })).reverse().slice(0, 5); // top 5 recent

        setRecentActivity(activity);
    }, []);

    return (
        <div className="min-h-screen bg-background text-on-surface">
            <Navbar />
            <div className="pt-28 pb-12 px-4 md:px-10 max-w-[1280px] mx-auto">
                <div className="flex justify-between items-center mb-8">
                    <div>
                        <h1 className="font-display-lg text-4xl font-bold text-primary">Panel de Control General</h1>
                        <p className="text-on-surface-variant text-lg">Visión global de la plataforma (Datos Reales del Sistema)</p>
                    </div>
                    <span className="bg-primary-fixed text-primary px-4 py-2 rounded-full font-bold text-sm">Modo Administrador</span>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-10">
                    <GlassCard className="rounded-[24px] p-6 flex items-center gap-4 border-l-4 border-l-primary">
                        <div className="w-14 h-14 rounded-full bg-primary-container text-on-primary-container flex items-center justify-center">
                            <Users size={24} />
                        </div>
                        <div>
                            <p className="text-on-surface-variant font-bold text-sm uppercase tracking-wide">Usuarios Reales Totales</p>
                            <p className="font-display-lg text-3xl font-bold">{stats.totalUsers}</p>
                            <p className="text-xs text-on-surface-variant mt-1">{stats.parents} Padres | {stats.sitters} Cuidadores</p>
                        </div>
                    </GlassCard>

                    <GlassCard className="rounded-[24px] p-6 flex items-center gap-4 border-l-4 border-l-secondary">
                        <div className="w-14 h-14 rounded-full bg-secondary-container text-on-secondary-container flex items-center justify-center">
                            <BookOpen size={24} />
                        </div>
                        <div>
                            <p className="text-on-surface-variant font-bold text-sm uppercase tracking-wide">Reservas Activas</p>
                            <p className="font-display-lg text-3xl font-bold">{stats.activeReservations}</p>
                            <p className="text-xs text-on-surface-variant mt-1">Pendientes o aceptadas</p>
                        </div>
                    </GlassCard>

                    <GlassCard className="rounded-[24px] p-6 flex items-center gap-4 border-l-4 border-l-error">
                        <div className="w-14 h-14 rounded-full bg-error-container text-on-error-container flex items-center justify-center">
                            <DollarSign size={24} />
                        </div>
                        <div>
                            <p className="text-on-surface-variant font-bold text-sm uppercase tracking-wide">Ingresos (Comisión 10%)</p>
                            <p className="font-display-lg text-3xl font-bold">${stats.totalIncome.toFixed(2)}</p>
                            <p className="text-xs text-on-surface-variant mt-1">Ganancia neta plataforma</p>
                        </div>
                    </GlassCard>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
                    <GlassCard className="rounded-[32px] p-8 lg:col-span-2">
                        <h2 className="font-display-lg text-2xl font-bold mb-6 flex items-center gap-2"><DollarSign className="text-primary"/> Desglose de Pagos por Cuidador</h2>
                        {paymentsBySitter.length > 0 ? (
                            <div className="overflow-x-auto">
                                <table className="w-full text-left border-collapse">
                                    <thead>
                                        <tr className="border-b-2 border-outline-variant/30">
                                            <th className="p-3 font-bold text-on-surface-variant uppercase text-sm">Cuidador</th>
                                            <th className="p-3 font-bold text-on-surface-variant uppercase text-sm">Trabajos Completados</th>
                                            <th className="p-3 font-bold text-on-surface-variant uppercase text-sm">Monto Generado</th>
                                            <th className="p-3 font-bold text-primary uppercase text-sm">Comisión (Plataforma)</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {paymentsBySitter.map((s, idx) => (
                                            <tr key={idx} className="border-b border-outline-variant/20 hover:bg-surface-container-low transition">
                                                <td className="p-3 font-bold">{s.name}</td>
                                                <td className="p-3">{s.completedJobs}</td>
                                                <td className="p-3">${s.totalGenerated.toFixed(2)}</td>
                                                <td className="p-3 font-bold text-primary">${s.commission.toFixed(2)}</td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        ) : (
                            <p className="text-on-surface-variant text-center py-4">Aún no hay trabajos completados y pagados en el sistema.</p>
                        )}
                    </GlassCard>

                    <GlassCard className="rounded-[32px] p-8">
                        <h2 className="font-display-lg text-2xl font-bold mb-6 flex items-center gap-2"><Clock className="text-primary"/> Esperando Pago del Padre</h2>
                        <div className="space-y-4">
                            {stats.pendingPayments > 0 ? (
                                <p className="text-center text-sm text-on-surface-variant mt-2">Hay {stats.pendingPayments} solicitudes aceptadas esperando el pago del padre.</p>
                            ) : (
                                <p className="text-center text-sm text-on-surface-variant mt-2">No hay pagos pendientes actualmente.</p>
                            )}
                        </div>
                    </GlassCard>

                    <GlassCard className="rounded-[32px] p-8">
                        <h2 className="font-display-lg text-2xl font-bold mb-6 flex items-center gap-2"><Activity className="text-secondary"/> Actividad Real Reciente</h2>
                        <div className="relative border-l-2 border-outline-variant/50 ml-4 space-y-6">
                            {recentActivity.length > 0 ? recentActivity.map((act, i) => (
                                <div key={i} className="relative pl-6">
                                    <div className={`absolute w-3 h-3 ${act.color} rounded-full left-[-7px] top-1`}></div>
                                    <p className="font-bold">{act.title}</p>
                                    <p className="text-sm text-outline">{act.desc}</p>
                                </div>
                            )) : (
                                <p className="text-sm text-on-surface-variant ml-4">No hay actividad registrada en la plataforma aún.</p>
                            )}
                        </div>
                    </GlassCard>
                </div>
            </div>
        </div>
    );
};

export default AdminDashboard;
